using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator;

    public ScoreCalculatorTests()
    {
        _calculator = new ScoreCalculator();
    }

    // ── CalculatePercentage ───────────────────────────────────────

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    [DataRow(1, 3, 33.333333333333336)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        var result = _calculator.CalculatePercentage(50, 50);

        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_IsInValidRange()
    {
        var result = _calculator.CalculatePercentage(3, 4);

        // Assert.IsInRange verifies the value falls within [low, high]
        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_ReturnsZero()
    {
        var result = _calculator.CalculatePercentage(0, 10);

        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_NegativeTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(1, -5));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // ── GetGrade ──────────────────────────────────────────────────

    [TestMethod]
    [DataRow(95.0, "A")]
    [DataRow(90.0, "A")]
    [DataRow(85.0, "B")]
    [DataRow(80.0, "B")]
    [DataRow(75.0, "C")]
    [DataRow(70.0, "C")]
    [DataRow(65.0, "D")]
    [DataRow(60.0, "D")]
    [DataRow(55.0, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_GivenPercentage_ReturnsExpectedGrade(double percentage, string expected)
    {
        var result = _calculator.GetGrade(percentage);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void GetGrade_AtBoundary89Point9_ReturnsB()
    {
        var result = _calculator.GetGrade(89.9);

        Assert.AreEqual("B", result);
    }

    [TestMethod]
    public void GetGrade_NegativePercentage_ReturnsF()
    {
        var result = _calculator.GetGrade(-10.0);

        Assert.AreEqual("F", result);
    }

    // ── NormalizeScore ────────────────────────────────────────────

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        var result = _calculator.NormalizeScore(50.0, 100.0);

        Assert.AreEqual(50.0, result);
    }

    [TestMethod]
    public void NormalizeScore_Result_IsAlwaysInRange()
    {
        var result = _calculator.NormalizeScore(75.0, 200.0);

        // Verify the normalized value is between 0 and 100 inclusive
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_IsCappedAt100()
    {
        var result = _calculator.NormalizeScore(150.0, 100.0);

        Assert.AreEqual(100.0, result);
        // Even though input exceeds max, result must not exceed 100
        Assert.IsLessThan(101.0, result);
    }

    [TestMethod]
    public void NormalizeScore_Zero_ReturnsZero()
    {
        var result = _calculator.NormalizeScore(0.0, 100.0);

        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_TypicalScore_IsGreaterThanZero()
    {
        var result = _calculator.NormalizeScore(30.0, 100.0);

        Assert.IsGreaterThan(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRawScore_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, 0.0));
    }

    [TestMethod]
    public void NormalizeScore_NegativeMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, -10.0));
    }
}

